-- Delete existing professional templates to avoid duplicates
DELETE FROM document_templates 
WHERE code IN ('INVOICE_PROFESSIONAL', 'QUOTE_PROFESSIONAL', 'LETTER_PROFESSIONAL', 'CONTRACT_PROFESSIONAL')
  AND organization_id IS NULL;

-- 1. FACTURA PROFESIONAL (category: billing)
INSERT INTO document_templates (
  code, name, description, document_type, style, category, 
  content_html, template_content, variables, 
  is_default, is_active, is_system_template, 
  show_logo, show_header, show_footer, layout
)
VALUES (
  'INVOICE_PROFESSIONAL',
  'Factura Profesional',
  'Diseño corporativo azul moderno',
  'invoice',
  'professional',
  'billing',
  '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Segoe UI,system-ui,sans-serif;background:#f5f7fa;color:#2d3748;line-height:1.6}.invoice{max-width:800px;margin:0 auto;background:#fff;box-shadow:0 4px 20px rgba(0,0,0,0.08)}.header{background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);padding:40px;display:flex;justify-content:space-between;align-items:flex-start}.header-left h1{color:#fff;font-size:28px;font-weight:600}.header-left p{color:rgba(255,255,255,0.8);font-size:13px;margin-top:5px}.header-right{background:rgba(255,255,255,0.15);padding:20px 25px;border-radius:8px;text-align:right}.header-right .label{color:rgba(255,255,255,0.7);font-size:11px;text-transform:uppercase;letter-spacing:1px}.header-right .value{color:#fff;font-size:24px;font-weight:700}.header-right .date{color:rgba(255,255,255,0.9);font-size:14px;margin-top:10px}.content{padding:40px}.info-grid{display:grid;grid-template-columns:1fr 1fr;gap:40px;margin-bottom:40px}.info-card{background:#f8fafc;padding:25px;border-radius:8px;border-left:4px solid #2563eb}.info-card h3{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#64748b;margin-bottom:15px}.info-card p{font-size:14px;margin:4px 0}.info-card .name{font-weight:600;font-size:16px;color:#1e3a5f}table{width:100%;border-collapse:collapse;margin:30px 0}thead{background:#1e3a5f}th{padding:15px 20px;text-align:left;color:#fff;font-size:12px;text-transform:uppercase;letter-spacing:1px}th:last-child{text-align:right}tbody tr{border-bottom:1px solid #e2e8f0}tbody tr:hover{background:#f8fafc}td{padding:18px 20px;font-size:14px}td:last-child{text-align:right;font-weight:600}.totals{display:flex;justify-content:flex-end;margin-top:20px}.totals-box{width:320px}.totals-row{display:flex;justify-content:space-between;padding:12px 20px}.totals-row:nth-child(odd){background:#f8fafc}.totals-row.total{background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);color:#fff;font-size:18px;font-weight:700;border-radius:8px;margin-top:10px}.footer{background:#f8fafc;padding:30px 40px;display:grid;grid-template-columns:1fr 1fr;gap:40px;border-top:1px solid #e2e8f0}.payment-box h4{font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#2563eb;margin-bottom:15px}.payment-box p{font-size:13px;color:#64748b;margin:3px 0}.notes-box h4{font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#2563eb;margin-bottom:15px}.notes-box p{font-size:13px;color:#64748b}</style></head><body><div class="invoice"><div class="header"><div class="header-left"><h1>{{empresa_nombre}}</h1><p>{{empresa_direccion}}</p><p>{{empresa_telefono}} | {{empresa_email}}</p></div><div class="header-right"><div class="label">Factura</div><div class="value">{{factura_numero}}</div><div class="date">{{factura_fecha}}</div></div></div><div class="content"><div class="info-grid"><div class="info-card"><h3>Datos del Cliente</h3><p class="name">{{cliente_nombre}}</p><p>{{cliente_direccion}}</p><p>CIF: {{cliente_cif}}</p><p>{{cliente_email}}</p></div><div class="info-card"><h3>Información de Factura</h3><p><strong>Fecha emisión:</strong> {{factura_fecha}}</p><p><strong>Vencimiento:</strong> {{factura_vencimiento}}</p><p><strong>Método pago:</strong> {{metodo_pago}}</p></div></div><table><thead><tr><th style="width:50%">Descripción del Servicio</th><th style="width:15%">Cantidad</th><th style="width:15%">Precio</th><th style="width:20%">Importe</th></tr></thead><tbody>{{#items}}<tr><td>{{descripcion}}</td><td>{{cantidad}}</td><td>{{precio}}</td><td>{{total}}</td></tr>{{/items}}</tbody></table><div class="totals"><div class="totals-box"><div class="totals-row"><span>Subtotal</span><span>{{subtotal}}</span></div><div class="totals-row"><span>IVA ({{iva_porcentaje}})</span><span>{{iva_importe}}</span></div><div class="totals-row total"><span>Total a Pagar</span><span>{{total_factura}}</span></div></div></div></div><div class="footer"><div class="payment-box"><h4>Datos Bancarios</h4><p><strong>Banco:</strong> {{banco_nombre}}</p><p><strong>IBAN:</strong> {{banco_iban}}</p></div><div class="notes-box"><h4>Notas</h4><p>{{notas}}</p></div></div></div></body></html>',
  'Factura Profesional Template',
  '{"empresa_nombre":{"label":"Empresa","required":true},"factura_numero":{"label":"Número","required":true},"items":{"label":"Líneas","type":"array"}}'::jsonb,
  true, true, true,
  true, true, true, 'professional'
);

