content:space-between;padding:12px 20px}.totals-row:nth-child(odd){background:#f8fafc}.totals-row.total{background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);color:#fff;font-size:18px;font-weight:700;border-radius:8px;margin-top:10px}.validity-box{background:linear-gradient(135deg,#dbeafe 0%,#eff6ff 100%);padding:25px;border-radius:8px;margin-bottom:30px;display:flex;align-items:center;gap:20px}.validity-icon{width:50px;height:50px;background:#2563eb;border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:24px}.validity-text h4{color:#1e3a5f;font-size:14px;margin-bottom:5px}.validity-text p{color:#64748b;font-size:13px}.terms{background:#f8fafc;padding:25px;border-radius:8px}.terms h4{color:#1e3a5f;font-size:12px;text-transform:uppercase;letter-spacing:1px;margin-bottom:15px}.terms p{color:#64748b;font-size:13px}.footer{background:#1e3a5f;padding:25px 40px;display:flex;justify-content:space-between;align-items:center}.footer p{color:rgba(255,255,255,0.8);font-size:13px}.footer-cta{background:#2563eb;color:#fff;padding:12px 25px;border-radius:6px;font-weight:600;font-size:14px}</style></head><body><div class="quote"><div class="header"><div class="header-top"><div class="header-left"><h1>{{empresa_nombre}}</h1><p>{{empresa_direccion}}</p></div><div class="header-right"><div class="label">Presupuesto</div><div class="value">{{presupuesto_numero}}</div></div></div><div class="project-banner"><div class="label">Proyecto</div><h2>{{proyecto_nombre}}</h2></div></div><div class="content"><div class="info-grid"><div class="info-card"><h3>Cliente</h3><p class="name">{{cliente_nombre}}</p><p>{{cliente_direccion}}</p><p>{{cliente_email}}</p></div><div class="info-card"><h3>Detalles</h3><p><strong>Fecha:</strong> {{presupuesto_fecha}}</p><p><strong>Contacto:</strong> {{empresa_telefono}}</p></div></div><table><thead><tr><th style="width:50%">Servicio / Concepto</th><th style="width:15%">Cantidad</th><th style="width:15%">Precio</th><th style="width:20%">Total</th></tr></thead><tbody>{{#items}}<tr><td>{{descripcion}}</td><td>{{cantidad}}</td><td>{{precio}}</td><td>{{total}}</td></tr>{{/items}}</tbody></table><div class="totals"><div class="totals-box"><div class="totals-row"><span>Subtotal</span><span>{{subtotal}}</span></div><div class="totals-row"><span>IVA ({{iva_porcentaje}})</span><span>{{iva_importe}}</span></div><div class="totals-row total"><span>Total</span><span>{{total_presupuesto}}</span></div></div></div><div class="validity-box"><div class="validity-icon">📅</div><div class="validity-text"><h4>Validez del Presupuesto</h4><p>Válido durante {{validez_dias}} días desde la emisión.</p></div></div><div class="terms"><h4>Condiciones</h4><p>{{condiciones}}</p></div></div><div class="footer"><p>{{empresa_email}} | {{empresa_telefono}}</p><div class="footer-cta">Aceptar Presupuesto</div></div></div></body></html>',
  'Presupuesto Profesional Template',
  '{"presupuesto_numero":{"label":"Número","required":true},"proyecto_nombre":{"label":"Proyecto","required":true},"items":{"label":"Líneas","type":"array"}}'::jsonb,
  true, true, true,
  true, true, true, 'professional'
);

-- 3. CARTA PROFESIONAL (category: correspondence)
INSERT INTO document_templates (
  code, name, description, document_type, style, category,
  content_html, template_content, variables,
  is_default, is_active, is_system_template,
  show_logo, show_header, show_footer, layout
