VALUES (
  'LETTER_PROFESSIONAL',
  'Carta Profesional',
  'Membrete corporativo azul',
  'letter',
  'professional',
  'correspondence',
  '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Segoe UI,system-ui,sans-serif;background:#f5f7fa;color:#2d3748;line-height:1.7}.letter{max-width:800px;margin:0 auto;background:#fff;min-height:1000px;display:flex;flex-direction:column;box-shadow:0 4px 20px rgba(0,0,0,0.08)}.header{background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);padding:30px 40px;display:flex;justify-content:space-between;align-items:center}.logo{color:#fff;font-size:24px;font-weight:600}.header-contact{text-align:right}.header-contact p{color:rgba(255,255,255,0.8);font-size:12px}.content{padding:50px;flex:1}.date-line{display:flex;justify-content:flex-end;margin-bottom:40px}.date-badge{background:#f1f5f9;padding:10px 20px;border-radius:6px;font-size:14px;color:#64748b}.recipient-card{background:#f8fafc;padding:25px;border-radius:8px;border-left:4px solid #2563eb;margin-bottom:40px}.recipient-card h3{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#64748b;margin-bottom:15px}.recipient-card .name{font-weight:600;font-size:18px;color:#1e3a5f}.recipient-card p{font-size:14px;margin:3px 0;color:#64748b}.subject-line{background:linear-gradient(135deg,#dbeafe 0%,#eff6ff 100%);padding:15px 25px;border-radius:8px;margin-bottom:35px}.subject-line span{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#2563eb}.subject-line h2{font-size:16px;color:#1e3a5f;margin-top:5px}.salutation{font-size:15px;margin-bottom:25px;color:#1e3a5f}.body-text{font-size:15px;color:#4a5568;text-align:justify}.body-text p{margin-bottom:18px}.closing{margin-top:35px;font-size:15px;color:#1e3a5f}.signature-block{margin-top:50px}.sig-line{width:250px;height:2px;background:linear-gradient(90deg,#2563eb,#60a5fa);margin-bottom:15px}.sig-name{font-size:18px;font-weight:600;color:#1e3a5f}.sig-title{font-size:13px;color:#64748b;margin-top:5px}.footer{background:#1e3a5f;padding:20px 40px;display:flex;justify-content:space-between;align-items:center}.footer p{color:rgba(255,255,255,0.8);font-size:12px}</style></head><body><div class="letter"><div class="header"><div class="logo">{{empresa_nombre}}</div><div class="header-contact"><p>{{empresa_direccion}}</p><p>{{empresa_telefono}} | {{empresa_email}}</p></div></div><div class="content"><div class="date-line"><div class="date-badge">{{lugar}}, {{fecha}}</div></div><div class="recipient-card"><h3>Destinatario</h3><p class="name">{{destinatario_nombre}}</p><p>{{destinatario_cargo}}</p><p>{{destinatario_empresa}}</p></div><div class="subject-line"><span>Asunto</span><h2>{{asunto}}</h2></div><div class="salutation">{{saludo}}</div><div class="body-text">{{cuerpo}}</div><div class="closing"><p>{{despedida}}</p></div><div class="signature-block"><div class="sig-line"></div><div class="sig-name">{{firmante_nombre}}</div><div class="sig-title">{{firmante_cargo}}</div></div></div><div class="footer"><p>CIF: {{empresa_cif}}</p><p>{{empresa_web}}</p></div></div></body></html>',
  'Carta Profesional Template',
  '{"destinatario_nombre":{"label":"Destinatario","required":true},"asunto":{"label":"Asunto","required":true},"cuerpo":{"label":"Cuerpo","required":true}}'::jsonb,
  true, true, true,
  true, true, true, 'professional'
);

-- 4. CONTRATO PROFESIONAL (category: contract)
INSERT INTO document_templates (
  code, name, description, document_type, style, category,
  content_html, template_content, variables,
  is_default, is_active, is_system_template,
  show_logo, show_header, show_footer, layout
)
VALUES (
  'CONTRACT_PROFESSIONAL',
  'Contrato Profesional',
  'Contrato corporativo azul',
  'contract',
  'professional',
  'contract',
  '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Segoe UI,system-ui,sans-serif;background:#f5f7fa;color:#2d3748;line-height:1.7}.contract{max-width:800px;margin:0 auto;background:#fff;box-shadow:0 4px 20px rgba(0,0,0,0.08)}.header{background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);padding:40px;text-align:center}.header h1{color:#fff;font-size:28px;font-weight:600;letter-spacing:4px}.header p{color:rgba(255,255,255,0.8);font-size:14px;margin-top:10px}.content{padding:50px}.intro-box{background:#f8fafc;padding:25px;border-radius:8px;text-align:center;margin-bottom:40px}.intro-box p{color:#64748b;font-size:14px}.intro-box .date{font-size:18px;color:#1e3a5f;font-weight:600;margin-top:10px}.parties-grid{display:grid;grid-template-columns:1fr 1fr;gap:30px;margin-bottom:40px}.party-card{background:#f8fafc;padding:25px;border-radius:8px;border-top:4px solid #2563eb}.party-card h3{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#2563eb;margin-bottom:15px}.party-card .name{font-weight:600;font-size:16px;color:#1e3a5f;margin-bottom:10px}.party-card p{font-size:13px;color:#64748b;margin:3px 0}.clause{margin-bottom:30px}.clause-header{display:flex;align-items:center;gap:15px;margin-bottom:15px}.clause-number{width:35px;height:35px;background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);color:#fff;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:600;font-size:14px}.clause-title{font-size:14px;font-weight:600;color:#1e3a5f;text-transform:uppercase;letter-spacing:1px}.clause-content{padding-left:50px}.clause-content p{font-size:14px;color:#4a5568;text-align:justify}.clause-content ul{margin:15px 0 15px 20px}.clause-content li{font-size:14px;color:#4a5568;margin-bottom:8px}.signatures{display:grid;grid-template-columns:1fr 1fr;gap:40px;margin-top:60px;padding-top:40px;border-top:2px solid #e2e8f0}.sig-block{text-align:center}.sig-block h4{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#64748b;margin-bottom:60px}.sig-line{height:2px;background:linear-gradient(90deg,#2563eb,#60a5fa);margin-bottom:15px}.sig-name{font-size:16px;font-weight:600;color:#1e3a5f}.sig-role{font-size:12px;color:#64748b;margin-top:5px}.footer{background:#1e3a5f;padding:20px 40px;text-align:center}.footer p{color:rgba(255,255,255,0.8);font-size:12px}</style></head><body><div class="contract"><div class="header"><h1>CONTRATO DE SERVICIOS</h1><p>{{contrato_tipo}}</p></div><div class="content"><div class="intro-box"><p>Contrato celebrado entre las partes en</p><div class="date">{{lugar}}, a {{fecha}}</div></div><div class="parties-grid"><div class="party-card"><h3>Primera Parte (Prestador)</h3><p class="name">{{empresa_nombre}}</p><p>CIF: {{empresa_cif}}</p><p>{{empresa_direccion}}</p></div><div class="party-card"><h3>Segunda Parte (Cliente)</h3><p class="name">{{cliente_nombre}}</p><p>CIF: {{cliente_cif}}</p><p>{{cliente_direccion}}</p></div></div><div class="clause"><div class="clause-header"><div class="clause-number">1</div><div class="clause-title">Objeto del Contrato</div></div><div class="clause-content"><p>{{clausula_objeto}}</p></div></div><div class="clause"><div class="clause-header"><div class="clause-number">2</div><div class="clause-title">Servicios a Prestar</div></div><div class="clause-content"><ul>{{#servicios}}<li>{{descripcion}}</li>{{/servicios}}</ul></div></div><div class="clause"><div class="clause-header"><div class="clause-number">3</div><div class="clause-title">Honorarios</div></div><div class="clause-content"><p>{{clausula_honorarios}}</p></div></div><div class="clause"><div class="clause-header"><div class="clause-number">4</div><div class="clause-title">Duración</div></div><div class="clause-content"><p>{{clausula_duracion}}</p></div></div><div class="signatures"><div class="sig-block"><h4>Por el Prestador</h4><div class="sig-line"></div><div class="sig-name">{{representante_empresa}}</div><div class="sig-role">{{cargo_representante}}</div></div><div class="sig-block"><h4>Por el Cliente</h4><div class="sig-line"></div><div class="sig-name">{{cliente_nombre}}</div></div></div></div><div class="footer"><p>{{empresa_nombre}} | {{empresa_telefono}} | {{empresa_email}}</p></div></div></body></html>',
  'Contrato Profesional Template',
  '{"contrato_tipo":{"label":"Tipo contrato","required":true},"clausula_objeto":{"label":"Objeto","required":true},"servicios":{"label":"Servicios","type":"array"}}'::jsonb,
  true, true, true,
  true, true, true, 'professional'
);